# Bicep: assign Contributor to a service principal at a resource group
param principalId string
param roleDefinitionId string = 'b24988ac-6180-42a0-ab88-20f7382dd24c' // Contributor

resource roleAssignment 'Microsoft.Authorization/roleAssignments@2022-04-01' = {
  name: guid(resourceGroup().id, principalId, roleDefinitionId)
  properties: {
    roleDefinitionId: subscriptionResourceId('Microsoft.Authorization/roleDefinitions', roleDefinitionId)
    principalId: principalId
    principalType: 'ServicePrincipal'
  }
}

# Terraform: role assignment
resource "azurerm_role_assignment" "app_contributor" {
  scope                = azurerm_resource_group.app.id
  role_definition_name = "Contributor"
  principal_id         = azurerm_user_assigned_identity.app.principal_id
}

# ARM template: role assignment
{
  "type": "Microsoft.Authorization/roleAssignments",
  "apiVersion": "2022-04-01",
  "name": "[guid(resourceGroup().id, parameters('principalId'), variables('contributorRoleId'))]",
  "properties": {
    "roleDefinitionId": "[subscriptionResourceId('Microsoft.Authorization/roleDefinitions', variables('contributorRoleId'))]",
    "principalId": "[parameters('principalId')]",
    "principalType": "ServicePrincipal"
  }
}

# Role assignment limits and quota management
# Limit: 4,000 role assignments per subscription
# (Custom + built-in combined; does not count PIM eligible assignments)

# Check current assignment count for a subscription
(Get-AzRoleAssignment -Scope '/subscriptions/SUB-ID').Count

# If nearing limit, prefer group assignments over individual user assignments
# One group assignment can cover hundreds of users with a single ARM resource

# Find subscriptions approaching the 4,000 limit
Get-AzSubscription | ForEach-Object {
    Set-AzContext -SubscriptionId $_.Id | Out-Null
    $count = (Get-AzRoleAssignment).Count
    [PSCustomObject]@{
        Subscription = $_.Name
        AssignmentCount = $count
        PercentUsed = [math]::Round($count/4000*100,1)
    }
} | Sort-Object PercentUsed -Descending | Format-Table -AutoSize

# Clean up orphaned assignments (principal no longer exists in Entra ID)
Get-AzRoleAssignment | Where-Object {
    $_.ObjectType -eq 'Unknown'
} | ForEach-Object {
    Write-Host "Orphaned: $($_.RoleAssignmentId)"
    # Remove-AzRoleAssignment -InputObject $_ -Confirm
}

# Bulk assignment from a CSV file
# assignments.csv columns: PrincipalUPN, RoleName, Scope
$assignments = Import-Csv -Path './assignments.csv'
foreach ($a in $assignments) {
    try {
        $principal = Get-AzADUser -UserPrincipalName $a.PrincipalUPN -ErrorAction Stop
        $existing = Get-AzRoleAssignment \`
            -ObjectId $principal.Id \`
            -RoleDefinitionName $a.RoleName \`
            -Scope $a.Scope \`
            -ErrorAction SilentlyContinue
        if ($null -eq $existing) {
            New-AzRoleAssignment \`
                -ObjectId $principal.Id \`
                -RoleDefinitionName $a.RoleName \`
                -Scope $a.Scope
            Write-Host "Assigned: $($a.RoleName) -> $($a.PrincipalUPN) at $($a.Scope)"
        } else {
            Write-Host "Exists: $($a.RoleName) -> $($a.PrincipalUPN) — skipped"
        }
    } catch {
        Write-Warning "Failed: $($a.PrincipalUPN) — $_"
    }
}

# Bulk removal: revoke all assignments for a specific role
Get-AzRoleAssignment -RoleDefinitionName 'Old Custom Role' |
    ForEach-Object {
        Remove-AzRoleAssignment -InputObject $_ -Confirm:$false
        Write-Host "Removed: $($_.DisplayName) at $($_.Scope)"
    }
